#include <stdio.h>

void tryToCheat(int hpClone) {
    hpClone = 999; // Only changes the clone!
}

int main() {
    int health = 100;
    tryToCheat(health);
    printf("Real health: %d\n", health); // Still 100!
    return 0;
}

#include <stdio.h>

// Expect an address!
void successfullyCheat(int *hpPtr) {
    *hpPtr = 999; // Follow the map, change the real value
}

int main() {
    int health = 100;
    successfullyCheat(&health); // Pass the map!
    printf("Real health: %d\n", health); // Now it's 999!
    return 0;
}
